import { CommonModule } from '@angular/common';
import { Component, OnInit, computed, inject, signal } from '@angular/core';
import { FormsModule } from '@angular/forms';
import { ChatService } from './services/chat.service';

@Component({
  selector: 'app-root',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './app.component.html',
  styleUrl: './app.component.css'
})
export class AppComponent implements OnInit {
  private readonly chatService = inject(ChatService);

  readonly loggedIn = signal(false);
  readonly usernameInput = signal('');
  readonly user = signal('');
  readonly message = signal('');
  readonly messages = this.chatService.messages;
  readonly connected = this.chatService.connected;
  readonly canSend = computed(() => this.message().trim().length > 0 && this.connected());

  async ngOnInit(): Promise<void> {
    await this.chatService.connect();
  }

  login(): void {
    const name = this.usernameInput().trim();
    if (!name) return;
    this.user.set(name);
    this.loggedIn.set(true);
  }

  logout(): void {
    this.loggedIn.set(false);
    this.user.set('');
    this.usernameInput.set('');
  }

  async send(): Promise<void> {
    const message = this.message().trim();
    if (!message) return;
    await this.chatService.sendMessage(this.user(), message);
    this.message.set('');
  }
}
<main class="chat-shell">

  <!-- LOGIN EKRANI -->
  <div class="login-overlay" *ngIf="!loggedIn()">
    <div class="login-card">
      <div class="login-logo">
        <i class="pi pi-comments"></i>
      </div>
      <h2>Sohbete Katıl</h2>
      <p class="login-sub">Kullanıcı adını gir ve başla</p>
      <div class="login-form">
        <input
          class="p-inputtext p-component login-input"
          type="text"
          placeholder="Kullanıcı adın"
          [ngModel]="usernameInput()"
          (ngModelChange)="usernameInput.set($event)"
          (keyup.enter)="login()"
          autofocus
        />
        <button
          class="p-button p-component login-btn"
          type="button"
          [disabled]="!usernameInput().trim()"
          (click)="login()"
        >
          <i class="pi pi-sign-in"></i>
          <span>Giriş Yap</span>
        </button>
      </div>
    </div>
  </div>

  <!-- SOHBET EKRANI -->
  <section class="chat-card p-component" *ngIf="loggedIn()">
    <div class="header-row">
      <h1>Sohbet</h1>
      <div class="header-right">
        <span class="status-tag" [class.online]="connected()" [class.offline]="!connected()">
          <i class="pi" [class.pi-check-circle]="connected()" [class.pi-times-circle]="!connected()"></i>
          {{ connected() ? 'Bağlı' : 'Bağlı değil' }}
        </span>
        <button class="user-chip" (click)="logout()" title="Çıkış yap">
          <i class="pi pi-user"></i>
          <span>{{ user() }}</span>
          <i class="pi pi-sign-out exit-icon"></i>
        </button>
      </div>
    </div>

    <section class="messages">
      <article
        class="msg"
        *ngFor="let item of messages()"
        [class.own]="item.user === user()"
      >
        <div class="msg-head">
          <strong>{{ item.user === user() ? 'Sen' : item.user }}</strong>
          <small>{{ item.sentAt | date: 'HH:mm' }}</small>
        </div>
        <p>{{ item.message }}</p>
      </article>

      <p class="empty" *ngIf="messages().length === 0">Henüz mesaj yok. İlk mesajı sen gönder.</p>
    </section>

    <section class="composer">
      <input
        class="p-inputtext p-component"
        type="text"
        placeholder="Mesajını yaz..."
        [ngModel]="message()"
        (ngModelChange)="message.set($event)"
        (keyup.enter)="send()"
      />
      <button class="p-button p-component" type="button" [disabled]="!canSend()" (click)="send()">
        <i class="pi pi-send"></i>
      </button>
    </section>
  </section>

</main>
